import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Linux에 Java 설치하기","description":"Linux에 Java를 설치하는 방법에 대한 단계별 가이드입니다.","frontmatter":{"title":"Linux에 Java 설치하기","description":"Linux에 Java를 설치하는 방법에 대한 단계별 가이드입니다.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.8/players/installing-java/linux.md","filePath":"versions/1.21.8/translated/ko_kr/players/installing-java/linux.md","lastUpdated":1760721669000}`);var o={name:`ko_kr/1.21.8/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Linux에 Java 설치하기 <a class="header-anchor" href="#h1" aria-label="Permalink to “Linux에 Java 설치하기”">​</a></h1><p>이 가이드는 Linux에 Java 21을 설치하는 과정을 안내해 줄 것입니다.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 이미 Java가 설치되었는지 확인하기 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 이미 Java가 설치되었는지 확인하기”">​</a></h2><p>터미널을 열고 <code>java -version</code>을 입력한 뒤, <kbd>Enter</kbd>를 누릅니다.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="&quot;java -version&quot;이 입력된 터미널" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Minecraft: Java Edition 1.21을 플레이 하려면, 적어도 Java 21 이상의 Java가 설치되어야 합니다. 만약 이 명령어가 Java 21보다 낮은 버전을 표시한다면, 기존의 Java 설치를 업데이트해야 합니다.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Java 21 다운로드하고 설치하기 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Java 21 다운로드하고 설치하기”">​</a></h2><p>대부분의 Linux 배포판에서 사용 가능한 OpenJDK 21을 사용하는 것을 권장합니다.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Arch Linux에 Java를 설치하는 방법에 대한 자세한 내용은 <a href="https://wiki.archlinux.org/title/Java" target="_blank" rel="noreferrer">Arch Linux 위키</a>를 참조하세요.</p></div><p>다음 명령어를 사용하여 공식 패키지 저장소에서 최신 JRE를 설치할 수 있습니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>그래픽 UI 없이 서버를 실행하려면, 헤드리스(headless) 버전을 설치할 수도 있습니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>모드를 개발하고자 한다면, JRE 대신 JDK를 설치해야 합니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>아래의 <code>apt</code> 명령어를 사용하여 Java 21을 설치할 수 있습니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>아래의 <code>dnf</code> 명령어를 사용하여 Java 21을 설치할 수 있습니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>그래픽 UI가 필요하지 않다면, 대신 헤드리스(headless) 버전을 설치할 수도 있습니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>모드를 개발하고자 한다면, JRE 대신 JDK를 설치해야 합니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="other-linux-distributions" tabindex="-1">기타 Linux 배포판 <a class="header-anchor" href="#other-linux-distributions" aria-label="Permalink to “기타 Linux 배포판”">​</a></h3><p>문서에 없는 배포판을 사용하고 있다면, <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a>에서 최신 JRE를 다운로드할 수 있습니다.</p><p>모드를 개발하고자 한다면 배포판의 다른 가이드를 참고해야 합니다.</p><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Java 21이 올바르게 설치되었는지 확인하기 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Java 21이 올바르게 설치되었는지 확인하기”">​</a></h2><p>설치 과정을 완료했다면, 터미널을 열고 <code>java -version</code>을 입력하여 Java 21이 올바르게 설치되었는지 확인할 수 있습니다.</p><p>명령어가 성공적으로 실행되었다면, 아래와 같이 Java 버전이 표시된 것을 확인할 수 있을 것입니다:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="&quot;java -version&quot;이 입력된 터미널" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};